var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"…그래서.","JPN":"……で。","ENG":"...So.","TWN":"所以…"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"맥스웰인지 뭔지가 맡긴 물건의 소유권은 그짝에 있으니, 죽기 싫으면 순순히 돌려달라?","JPN":"マックスウェルとかが預けたものの所有権はそっちにあるから、死にたくなかったら素直に返せと？","ENG":"Since you have ownership of this Maxwell fellow's item, you want me to hand it over to you if I want to live?","TWN":"你的意思是那個叫麥斯威爾還是什麼的人，抵押在我們這邊的東西是屬於你們的，不想死的話就乖乖把東西交出來？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"…푸.","JPN":"……ぷっ。","ENG":"...Pfft.","TWN":"噗…"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"푸하하하! 들었냐 얘들아? 웬 계집애 둘이 와서는, 이런 걸 협박이라고 하고 있단다!","JPN":"ガハハハッ！　おい、聞いたか？　お嬢ちゃん二人で来ておいて、脅かすつもりなのかよ！","ENG":"HAHAHAHA! Did y'all hear that? A couple of girls walk in here and are trying to threaten ME!","TWN":"噗哈哈哈！你們有聽到嗎？這二個丫頭在威脅我們欸？！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"아빠가 사줬는지 호위용 드론까지 대동하고 말이야. 흐하하하하!","JPN":"パパから買ってもらった護衛用のドローンまで連れて来てさ。フハハハハ！","ENG":"Along with some bodyguard drone that her daddy must've bought her. HAHAHAHAHA!","TWN":"還加上一台疑似是爸爸買給她們的無人機玩具，哈哈哈哈！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"효율성 위주의 소체가 호위용으로 전락하다니. 진공관 맙소사.","JPN":"効率性を第一にしている素体が、護衛用に転落するとは。オーマイ真空管。","ENG":"I cannot believe my efficiency-oriented drone is being called a bodyguard. Oh my diodes.","TWN":"我的真空管，好好的一個高效能機體被你說成是玩具。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"뇌세포의 접점 과정에서 문제가 생긴 것 같군요, 휴먼. 조속한 치료를 권장합니다.","JPN":"脳細胞の接点過程で問題が発生したようですね、ヒューマン。直ちに治療することをおすすめします。","ENG":"It seems there is a problem with your brain cells processing information, human. I recommend you get treatment immediately.","TWN":"人類，我看你的腦細胞可能有病變，建議你盡速接受治療。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이봐, 우린 농담 따먹기나 하려고 여기까지 온 게 아니야.","JPN":"おい、冗談言うためにここまで来たわけでじゃないんだ。","ENG":"Hey, you think we're here to joke around?","TWN":"喂，我們是來這裡開玩笑的嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"역설적이지만 카지노에 온 사람들이 가장 바라는 건 공정이지. 사장인 당신은 그 규율을 어겼고.","JPN":"逆説的だが、カジノに来た人たちが一番求めていることはフェアだ。社長であるあんたは、その規律を違反した。","ENG":"It's ironic, but the people who come to casinos hope for fairness. But you, the owner of this establishment, broke the rules.","TWN":"雖然有點矛盾，但來賭場的人他們在意的就是公平，但你身為賭場老闆卻破壞這個規則。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아티팩트 하나 보존하는 게 사업장을 망치는 것보다 이득이라 생각하는 건가?","JPN":"アーティファクト一つを保存することが、事業をダメにすることより得だと思ってるのか？","ENG":"Do you really believe keeping an Artifact is better than keeping this place intact?","TWN":"你認為人造神器比你的賭場生意還重要嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"…청록빛 머리카락의 사채업자. 그래, 네가 리타 아르세니코인가 보군.","JPN":"……青緑の髪の闇金業者。そうか、お前がリタ・アルセニコなのか。","ENG":"...A loan shark with turquoise hair. Yeah, you're Rita Arsenico.","TWN":"…綠色頭髮的高利貸業者，嗯，你就是麗塔·阿塞妮克吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"소문은 익히 들어 알고 있지. 주제파악 못 하고 나대는 애송이라는 것도 말이야.","JPN":"噂は聞いてるぜ。身の程知らずで調子乗ってる小娘だってこともな。","ENG":"I've heard a lot about you. And how you're a kid who doesn't know her place.","TWN":"還有你身旁那個不知道天高地厚的丫頭，久仰大名呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"아직도 과거의 편린이 남아 있다 생각하는 건가? 지금의 넌 형편 좋게 부리는 개 한 마리일 뿐이야.","JPN":"まだ過去の片鱗が残ってると思うのか？　今のお前は都合よく使われてる一匹の犬に過ぎないぞ。","ENG":"Do you still think you are who you once were? You're nothing but a well-behaved dog now.","TWN":"你以為你還像過去那樣威風嗎？現在的你只剩一條狗能使喚。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"그렇지만… 그래. 틀린 말은 아니지.","JPN":"でも……ああ。間違ってはいない。","ENG":"But... Yes, you have a point.","TWN":"不過…你說的沒錯，"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"그렇다면 이렇게 하는 건 어떤가?","JPN":"なら、これはどうだ？","ENG":"Then how about this?","TWN":"那這樣如何？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"주사위?","JPN":"サイコロ？","ENG":"Dice?","TWN":"骰子？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"평범한 주사위 포커야. 주사위를 던져 높은 족보가 나오는 쪽이 이기는 간단한 게임이지.","JPN":"普通のポーカーダイスだ。サイコロを投げて出た目が強い方が勝つ、シンプルなゲームさ。","ENG":"They are just normal poker dice. A simple game of poker dice where whoever gets the highest hand wins.","TWN":"就玩普通的骰子撲克吧。雙方擲骰子，得分多的一方獲勝。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"일대일 게임을 해서 이기는 쪽이 모두 가진다. 쉽지?","JPN":"1対1のゲームで勝った方がすべてを得る。簡単だろ？","ENG":"You and I play, and the winner gets everything. Easy, no?","TWN":"一對一進行，贏的那方通吃，很簡單吧？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FOOLSDAY_CEO_NPC_NULL","text":{"KOREA":"아, 주사위는 평범한 주사위니 걱정하지 않아도 좋아. 철이라서 다소 무겁긴 하지만.","JPN":"あ、サイコロは普通のサイコロだから心配しなくていい。鉄で少し重いがな。","ENG":"Oh, don't worry about the dice being loaded. They're just heavy from being made of metal.","TWN":"你放心，這只是一般的骰子，只是因為是鐵做的所以有點重。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"좋습니다. 그럼 저희는 리타의 1년 치 월급을 걸죠.","JPN":"いいでしょう。それでは、私たちはリタの1年分の給料を賭けます。","ENG":"Very well. Then we will bet a year of Rita's salary.","TWN":"好，那我們的賭注是麗塔一年的薪水。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"FOOLSDAY_CEO_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}}]`);export{e as default};